2413	    case kIROp_Poison:
2414	    case kIROp_DefaultConstruct:
2415	        m_writer->emit(getName(inst));
2416	        break;
2417	
2418	    case kIROp_IntLit:
2419	    case kIROp_FloatLit:
2420	    case kIROp_BoolLit:
2421	        emitSimpleValue(inst);
2422	        break;
2423	
2424	    case kIROp_MakeCoopVector:
2425	    case kIROp_MakeVector:
2426	    case kIROp_MakeMatrix:
2427	    case kIROp_VectorReshape:
2428	    case kIROp_CastFloatToInt:
2429	    case kIROp_CastIntToFloat:
2430	    case kIROp_IntCast:
2431	    case kIROp_FloatCast:
2432	        // Simple constructor call
