2442	            SLANG_RELEASE_ASSERT(columnCount);
2443	            auto rowCount = as<IRIntLit>(matrixType->getRowCount());
2444	            SLANG_RELEASE_ASSERT(rowCount);
2445	            m_writer->emit("(");
2446	            for (IRIntegerValue i = 0; i < rowCount->getValue() * columnCount->getValue(); i++)
2447	            {
