2461	        m_writer->emit("((");
2462	        emitType(inst->getDataType());
2463	        m_writer->emit("(");
2464	        emitOperand(inst->getOperand(1), getInfo(EmitOp::General));
2465	        m_writer->emit(") << 32) + ");
2466	        emitOperand(inst->getOperand(0), getInfo(EmitOp::General));
