bool maybeSpecializeWitnessLookup(IRLookupWitnessMethod* lookupInst)
{
    // Note: While we currently have named the instruction
    // `lookup_witness_method`, the `method` part is a misnomer
    // and the same instruction can look up *any* interface
    // requirement based on the witness table that provides
    // a conformance, and the "key" that indicates the interface
    // requirement.

    // We can only specialize in the case where the lookup
    // is being done on a concrete witness table, and not
    // the result of a `specialize` instruction or other
    // operation that will yield such a table.
    //
    // Since we unify the frontend such that all LookupDeclRef node
    // on a interface requirement will always be lowered to lookup
    // witness, it creats an exception that IRThisTypeWitness, a non-concrete
    // witness table, also need to be specialized. Otherwise, there is
    // no logic in the later passes can handle it. However, we know for
    // sure that the IRThisTypeWitness is only used to wrap an interface
    // type, therefore, it must be only used to exact the interface requirement.
    auto witnessTable = as<IRWitnessTable>(lookupInst->getWitnessTable());
    IRInterfaceType* interfaceType = nullptr;
    if (!witnessTable)
    {
        if (auto witnessTableSet = as<IRWitnessTableSet>(lookupInst->getWitnessTable()))
        {
            auto requirementKey = lookupInst->getRequirementKey();

            HashSet<IRInst*> satisfyingValSet;
            bool skipSpecialization = false;
            forEachInSet(
                module,
                witnessTableSet,
                [&](IRInst* instElement)
                {
                    if (auto table = as<IRWitnessTable>(instElement))
                    {
                        if (auto satisfyingVal = findWitnessTableEntry(table, requirementKey))
                        {
                            satisfyingValSet.add(satisfyingVal);
                            return;
                        }
                    }

                    // If we reach here, we didn't find a satisfying value.
                    skipSpecialization = true;
                });

            if (!skipSpecialization)
            {
                IRBuilder builder(module);
                auto setOp = getSetOpFromType(lookupInst->getDataType());
                auto newSet = builder.getSet(setOp, satisfyingValSet);
                addUsersToWorkList(lookupInst);
                if (as<IRTypeSet>(newSet))
                {
                    lookupInst->replaceUsesWith(builder.getUntaggedUnionType(newSet));
                    lookupInst->removeAndDeallocate();
                }
                else if (as<IRWitnessTableSet>(newSet))
                {
                    lookupInst->replaceUsesWith(newSet);
                    lookupInst->removeAndDeallocate();
                }
                else
                {
                    // Should not see any other case.
                    SLANG_UNREACHABLE("unexpected set kind");
                }

                return true;
            }
            else
                return false;
        }
        else if (auto thisTypeWitness = as<IRThisTypeWitness>(lookupInst->getWitnessTable()))
        {
            if (auto witnessTableType =
                    as<IRWitnessTableTypeBase>(thisTypeWitness->getDataType()))

        // for a builtin type/function, or some of the type arguments are unknown at compile
        // time, in which case we will rely on a follow up pass the translate it into a
        // dynamic dispatch function.
        //
        // Now we consider lower lookupWitnessMethod insts into dynamic dispatch calls,
        // which may open up more specialization opportunities.
        //
        if (options.lowerWitnessLookups)
        {
            bool dynPassChanged = specializeDynamicInsts(
                module,
                targetProgram,
                sink,
                this,
                options.reportDynamicDispatchSites);

            if (dynPassChanged)
                eliminateDeadCode(module->getModuleInst());

            iterChanged |= dynPassChanged;
        }

        if (!iterChanged || sink->getErrorCount())
            break;
    }
}

void addInstsToWorkListRec(IRInst* inst)
{
    addToWorkList(inst);

    for (auto child = inst->getLastChild(); child; child = child->getPrevInst())
    {
        addInstsToWorkListRec(child);
    }
}

