            auto func = getFuncDefinitionForContext(context);
            SLANG_ASSERT(func);
            IRType* returnType = cast<IRFuncType>(func->getDataType())->getResultType();
            updateFuncReturnInfo(context, tryGetArgInfo(context, val, returnType), workQueue);
        }
    }
};

